export function processOrder(order: any): any {
  if (!order) return null;
  if (!order.items || order.items.length === 0) return { error: 'no items' };
  let total = 0;
  for (let i = 0; i < order.items.length; i++) {
    total += order.items[i].price * order.items[i].qty;
  }
  if (order.user && order.user.isVip) total = total * 0.9;
  if (order.coupon === 'SUMMER') total = total - 5;
  if (order.shippingCountry === 'US') total = total + 10;
  else if (order.shippingCountry === 'CA') total = total + 15;
  else total = total + 25;
  console.log('Processed order:', total);
  return { total: total };
}
